void display() {
 glClear(GL_COLOR_BUFFER_BIT | GL_DEPTH_BUFFER_BIT);
 glLoadIdentity();
 glTranslatef(2.0f, 1.5f, 0.0f); // Translate right and up

 // Draw colored cube
 glutWireCube(1.0); // 1 unit size cube

 glFlush();
}

void display() {
 glClear(GL_COLOR_BUFFER_BIT);
 glMatrixMode(GL_MODELVIEW);
 glLoadIdentity();
 glScalef(2.0f, 0.5f, 1.0f); // Double width, halve height

 // Draw object (e.g. cube)
 glutSolidCube(1.0);

 glutSwapBuffers();
}

void display() {
 glClear(GL_COLOR_BUFFER_BIT);
 glLoadIdentity();

 // Order: Scale then Translate
 glTranslatef(3.0f, 0.0f, 0.0f);
 glScalef(2.0f, 2.0f, 1.0f);

 glutWireSphere(0.5, 20, 20); // Draw sphere

 glutSwapBuffers();
}

// Result: Sphere is first scaled, then translated
